import java.util.LinkedList;
import java.util.Queue;

public class Main {
    public static void main(String[] args) {
        int[][] grid = {
            {1, 1, 0},
            {1, 1, 0},
            {0, 0, 1}
        };

        Queue<int[]> queue = new LinkedList<>();
        boolean[][] visited = new boolean[3][3];

        queue.offer(new int[]{0, 0});
        visited[0][0] = true;
        int count = 0;

        int[][] dirs = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};
        while (!queue.isEmpty()) {
            int[] cell = queue.poll();
            count++;
            for (int[] d : dirs) {
                int nr = cell[0] + d[0], nc = cell[1] + d[1];
                if (nr >= 0 && nr < 3 && nc >= 0 && nc < 3 && !visited[nr][nc] && grid[nr][nc] == 1) {
                    visited[nr][nc] = true;
                    queue.offer(new int[]{nr, nc});
                }
            }
        }
        System.out.println("Connected cells: " + count);  // Connected cells: 4
    }
}

